<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>WastedToken Mint</title>
<style>
  :root {
    --bg: #0d0d0d;
    --fg: #f0f0f0;
    --accent: #d4a817;
    --card: #1a1a1a;
    --muted: #888;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: var(--bg);
    color: var(--fg);
    line-height: 1.6;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
  }
  header {
    padding: 2rem 1rem;
    text-align: center;
    background: linear-gradient(180deg, #1a1a1a 0%, var(--bg) 100%);
  }
  #coin-hero {
    display: block;
    max-width: 600px;
    width: 100%;
    height: auto;
    margin: 0 auto;
    background: var(--bg);
    border-radius: 50%;
    box-shadow: 0 0 60px -10px rgba(212,168,23,0.3), inset 0 0 60px -10px rgba(0,0,0,0.8);
  }
  main { flex: 1; padding: 2rem 1rem; max-width: 1000px; margin: 0 auto; width: 100%; }
  section { margin-bottom: 3rem; }
  h2 { font-size: 1.8rem; margin-bottom: 1rem; color: var(--accent); letter-spacing: 0.02em; }
  p { color: var(--muted); max-width: 70ch; }
  .grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 1.5rem;
  }
  .edition {
    background: var(--card);
    border-radius: 12px;
    overflow: hidden;
    position: relative;
    border: 1px solid #333;
    transition: transform 0.2s, box-shadow 0.2s;
  }
  .edition:hover { transform: translateY(-4px); box-shadow: 0 12px 24px -8px rgba(0,0,0,0.5); }
  .edition-canvas { display: block; width: 100%; height: auto; background: var(--card); }
  .edition .status {
    padding: 0.75rem;
    text-align: center;
    font-weight: 600;
    font-size: 0.85rem;
    letter-spacing: 0.05em;
  }
  .edition[data-state="sold-out"] .status { color: #e04040; background: rgba(224,64,64,0.1); }
  .edition[data-state="coming-soon"] .status { color: #e8a838; background: rgba(232,168,56,0.1); }
  .buy {
    display: block;
    width: 100%;
    padding: 0.85rem;
    background: linear-gradient(180deg, #f0c840, var(--accent));
    color: #111;
    border: none;
    font: 600 0.9rem inherit;
    cursor: pointer;
    transition: opacity 0.2s, transform 0.1s;
  }
  .buy:hover { opacity: 0.9; }
  .buy:active { transform: scale(0.98); }
  .buy:disabled { opacity: 0.4; cursor: not-allowed; }
  footer { padding: 2rem; text-align: center; color: var(--muted); font-size: 0.8rem; border-top: 1px solid #222; }
</style>
</head>
<body>
<header>
  <canvas id="coin-hero" width="600" height="600"></canvas>
</header>
<main>
  <section id="about">
    <h2>About WastedToken Mint</h2>
    <p>
      Founded in 2018, WastedToken Mint has redefined the art of the challenge coin.
      Each piece is struck from proprietary alloys using century‑old coining presses,
      then hand‑finished to bring out a depth of relief that catches light like liquid metal.
      Our coins are not mere tokens — they are pocket‑sized monuments to the moments,
      missions, and communities that define us. From the warm glow of Bronze to the
      obsidian mystery of Black, every edition tells a story you can feel in your hand.
    </p>
  </section>
  <section id="collection">
    <h2>Editions</h2>
    <div class="grid">
      <div class="edition" data-edition="bronze" data-state="available">
        <canvas class="edition-canvas" width="200" height="200"></canvas>
        <button class="buy">Add to cart</button>
      </div>
      <div class="edition" data-edition="silver" data-state="available">
        <canvas class="edition-canvas" width="200" height="200"></canvas>
        <button class="buy">Add to cart</button>
      </div>
      <div class="edition" data-edition="gold" data-state="sold-out">
        <canvas class="edition-canvas" width="200" height="200"></canvas>
        <div class="status">SOLD OUT</div>
      </div>
      <div class="edition" data-edition="black" data-state="coming-soon">
        <canvas class="edition-canvas" width="200" height="200"></canvas>
        <div class="status">MINTING AUTUMN 2025</div>
      </div>
    </div>
  </section>
</main>
<footer>
  WastedToken Mint &copy; 2025 — Struck with purpose.
</footer>
<script>
// ============ WebGL Hero Coin ============
const heroCanvas = document.getElementById('coin-hero');
const gl = heroCanvas.getContext('webgl', { antialias: true, alpha: false, depth: true });
if (!gl) throw new Error('WebGL not supported');

// --- Shaders ---
const vsSource = `
attribute vec3 aPosition;
attribute vec3 aNormal;
attribute float aFaceType;
attribute float aAngle;
attribute vec2 aTexCoord;
uniform mat4 uModelView;
uniform mat4 uProjection;
uniform mat3 uNormalMatrix;
varying vec3 vNormal;
varying vec3 vViewPos;
varying float vFaceType;
varying float vAngle;
varying vec2 vTexCoord;
void main() {
  vec4 viewPos = uModelView * vec4(aPosition, 1.0);
  vViewPos = viewPos.xyz;
  vNormal = normalize(uNormalMatrix * aNormal);
  vFaceType = aFaceType;
  vAngle = aAngle;
  vTexCoord = aTexCoord;
  gl_Position = uProjection * viewPos;
}
`;
const fsSource = `
precision highp float;
varying vec3 vNormal;
varying vec3 vViewPos;
varying float vFaceType;
varying float vAngle;
varying vec2 vTexCoord;
uniform vec3 uLightDir;
uniform vec3 uViewPos;
uniform sampler2D uFrontTexture;
uniform sampler2D uBackTexture;
uniform vec3 uMetalColor;
uniform float uShininess;
void main() {
  vec3 N = normalize(vNormal);
  vec3 V = normalize(-vViewPos);
  vec3 L = normalize(uLightDir);
  vec3 H = normalize(L + V);
  float diff = max(dot(N, L), 0.0);
  float spec = pow(max(dot(N, H), 0.0), uShininess);
  vec3 color;
  if (vFaceType < 0.5) { // edge
    color = uMetalColor;
    float ridge = sin(vAngle * 32.0) * 0.5 + 0.5;
    spec *= ridge;
    color *= 0.7 + 0.3 * ridge;
  } else if (vFaceType < 1.5) { // front
    vec4 tex = texture2D(uFrontTexture, vTexCoord);
    float base = 0.3 + 0.7 * tex.r;
    color = uMetalColor * base * (diff * 0.5 + 0.5) + uMetalColor * spec * 2.0;
  } else { // back
    vec4 tex = texture2D(uBackTexture, vTexCoord);
    float base = 0.3 + 0.7 * tex.r;
    color = uMetalColor * base * (diff * 0.5 + 0.5) + uMetalColor * spec * 2.0;
  }
  color += uMetalColor * 0.08; // ambient
  gl_FragColor = vec4(color, 1.0);
}
`;

function createShader(gl, type, source) {
  const shader = gl.createShader(type);
  gl.shaderSource(shader, source);
  gl.compileShader(shader);
  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    console.error(gl.getShaderInfoLog(shader));
    gl.deleteShader(shader);
    return null;
  }
  return shader;
}
function createProgram(gl, vs, fs) {
  const program = gl.createProgram();
  gl.attachShader(program, vs);
  gl.attachShader(program, fs);
  gl.linkProgram(program);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    console.error(gl.getProgramInfoLog(program));
    return null;
  }
  return program;
}

const vs = createShader(gl, gl.VERTEX_SHADER, vsSource);
const fs = createShader(gl, gl.FRAGMENT_SHADER, fsSource);
const program = createProgram(gl, vs, fs);
if (!program) throw new Error('Shader program failed');

// --- Attribute / Uniform locations ---
const aPosition = gl.getAttribLocation(program, 'aPosition');
const aNormal = gl.getAttribLocation(program, 'aNormal');
const aFaceType = gl.getAttribLocation(program, 'aFaceType');
const aAngle = gl.getAttribLocation(program, 'aAngle');
const aTexCoord = gl.getAttribLocation(program, 'aTexCoord');
const uModelView = gl.getUniformLocation(program, 'uModelView');
const uProjection = gl.getUniformLocation(program, 'uProjection');
const uNormalMatrix = gl.getUniformLocation(program, 'uNormalMatrix');
const uLightDir = gl.getUniformLocation(program, 'uLightDir');
const uViewPos = gl.getUniformLocation(program, 'uViewPos');
const uFrontTexture = gl.getUniformLocation(program, 'uFrontTexture');
const uBackTexture = gl.getUniformLocation(program, 'uBackTexture');
const uMetalColor = gl.getUniformLocation(program, 'uMetalColor');
const uShininess = gl.getUniformLocation(program, 'uShininess');

// --- Geometry ---
const segments = 64;
const radius = 1.0;
const halfHeight = 0.05;

function createBuffers(data) {
  const buf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, buf);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(data), gl.STATIC_DRAW);
  return buf;
}

// Front cap (TRIANGLE_FAN)
const frontPos = [], frontNorm = [], frontFace = [], frontAngle = [], frontUV = [];
frontPos.push(0,0,halfHeight); frontNorm.push(0,0,1); frontFace.push(1); frontAngle.push(0); frontUV.push(0.5,0.5);
for (let i=0;i<segments;i++) {
  const a = i*2*Math.PI/segments, x=Math.cos(a), y=Math.sin(a);
  frontPos.push(x,y,halfHeight); frontNorm.push(0,0,1); frontFace.push(1); frontAngle.push(0);
  frontUV.push(0.5+0.5*x, 0.5+0.5*y);
}
const frontCount = 1+segments;
const frontBuffers = {
  position: createBuffers(frontPos),
  normal: createBuffers(frontNorm),
  faceType: createBuffers(frontFace),
  angle: createBuffers(frontAngle),
  texCoord: createBuffers(frontUV)
};

// Back cap (TRIANGLE_FAN)
const backPos = [], backNorm = [], backFace = [], backAngle = [], backUV = [];
backPos.push(0,0,-halfHeight); backNorm.push(0,0,-1); backFace.push(2); backAngle.push(0); backUV.push(0.5,0.5);
for (let i=0;i<segments;i++) {
  const a = i*2*Math.PI/segments, x=Math.cos(a), y=Math.sin(a);
  backPos.push(x,y,-halfHeight); backNorm.push(0,0,-1); backFace.push(2); backAngle.push(0);
  backUV.push(0.5+0.5*x, 0.5+0.5*y);
}
const backCount = 1+segments;
const backBuffers = {
  position: createBuffers(backPos),
  normal: createBuffers(backNorm),
  faceType: createBuffers(backFace),
  angle: createBuffers(backAngle),
  texCoord: createBuffers(backUV)
};

// Side (TRIANGLE_STRIP)
const sidePos = [], sideNorm = [], sideFace = [], sideAngle = [], sideUV = [];
for (let i=0;i<=segments;i++) {
  const a = (i%segments)*2*Math.PI/segments, x=Math.cos(a), y=Math.sin(a);
  // top
  sidePos.push(x,y,halfHeight); sideNorm.push(x,y,0); sideFace.push(0); sideAngle.push(a); sideUV.push(0,0);
  // bottom
  sidePos.push(x,y,-halfHeight); sideNorm.push(x,y,0); sideFace.push(0); sideAngle.push(a); sideUV.push(0,0);
}
const sideCount = (segments+1)*2;
const sideBuffers = {
  position: createBuffers(sidePos),
  normal: createBuffers(sideNorm),
  faceType: createBuffers(sideFace),
  angle: createBuffers(sideAngle),
  texCoord: createBuffers(sideUV)
};

function bindBuffers(bufs) {
  gl.bindBuffer(gl.ARRAY_BUFFER, bufs.position); gl.vertexAttribPointer(aPosition, 3, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(aPosition);
  gl.bindBuffer(gl.ARRAY_BUFFER, bufs.normal);   gl.vertexAttribPointer(aNormal, 3, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(aNormal);
  gl.bindBuffer(gl.ARRAY_BUFFER, bufs.faceType); gl.vertexAttribPointer(aFaceType, 1, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(aFaceType);
  gl.bindBuffer(gl.ARRAY_BUFFER, bufs.angle);    gl.vertexAttribPointer(aAngle, 1, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(aAngle);
  gl.bindBuffer(gl.ARRAY_BUFFER, bufs.texCoord); gl.vertexAttribPointer(aTexCoord, 2, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(aTexCoord);
}

// --- Textures ---
function createTextureFromCanvas(canvas) {
  const tex = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, tex);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, canvas);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  return tex;
}

function makeFrontTexture() {
  const size = 256;
  const c = document.createElement('canvas'); c.width = size; c.height = size;
  const ctx = c.getContext('2d');
  const cx = size/2, cy = size/2, r = size/2 - 2;
  ctx.fillStyle = '#808080'; ctx.fillRect(0,0,size,size);
  ctx.beginPath(); ctx.arc(cx,cy,r,0,Math.PI*2); ctx.fillStyle = '#808080'; ctx.fill();
  ctx.fillStyle = '#ffffff';
  ctx.font = 'bold 110px serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.fillText('W', cx, cy);
  return c;
}
function makeBackTexture() {
  const size = 256;
  const c = document.createElement('canvas'); c.width = size; c.height = size;
  const ctx = c.getContext('2d');
  const cx = size/2, cy = size/2;
  ctx.fillStyle = '#808080'; ctx.fillRect(0,0,size,size);
  ctx.fillStyle = '#ffffff';
  ctx.font = 'bold 42px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.fillText('10,000', cx, cy - 22);
  ctx.fillText('TOKENS', cx, cy + 22);
  return c;
}

const frontTexture = createTextureFromCanvas(makeFrontTexture());
const backTexture = createTextureFromCanvas(makeBackTexture());

// --- Matrix math ---
function mat4Perspective(fov, aspect, near, far) {
  const f = 1.0 / Math.tan(fov/2);
  return [
    f/aspect, 0, 0, 0,
    0, f, 0, 0,
    0, 0, (far+near)/(near-far), -1,
    0, 0, (2*far*near)/(near-far), 0
  ];
}
function mat4LookAt(eye, center, up) {
  const f = [center[0]-eye[0], center[1]-eye[1], center[2]-eye[2]];
  const fl = Math.hypot(...f); f[0]/=fl; f[1]/=fl; f[2]/=fl;
  const s = [f[1]*up[2]-f[2]*up[1], f[2]*up[0]-f[0]*up[2], f[0]*up[1]-f[1]*up[0]];
  const sl = Math.hypot(...s); s[0]/=sl; s[1]/=sl; s[2]/=sl;
  const u = [s[1]*f[2]-s[2]*f[1], s[2]*f[0]-s[0]*f[2], s[0]*f[1]-s[1]*f[0]];
  return [
    s[0], u[0], -f[0], 0,
    s[1], u[1], -f[1], 0,
    s[2], u[2], -f[2], 0,
    -(s[0]*eye[0]+s[1]*eye[1]+s[2]*eye[2]),
    -(u[0]*eye[0]+u[1]*eye[1]+u[2]*eye[2]),
    f[0]*eye[0]+f[1]*eye[1]+f[2]*eye[2], 1
  ];
}
function mat4Multiply(a, b) {
  const r = [];
  for (let i=0;i<4;i++) for (let j=0;j<4;j++) {
    let v=0; for (let k=0;k<4;k++) v+=a[i*4+k]*b[k*4+j]; r.push(v);
  }
  return r;
}
function mat4RotateX(a) {
  const c=Math.cos(a), s=Math.sin(a);
  return [1,0,0,0, 0,c,s,0, 0,-s,c,0, 0,0,0,1];
}
function mat4RotateY(a) {
  const c=Math.cos(a), s=Math.sin(a);
  return [c,0,-s,0, 0,1,0,0, s,0,c,0, 0,0,0,1];
}
function mat4MultiplyVec3(m, v) {
  return [
    m[0]*v[0]+m[4]*v[1]+m[8]*v[2],
    m[1]*v[0]+m[5]*v[1]+m[9]*v[2],
    m[2]*v[0]+m[6]*v[1]+m[10]*v[2]
  ];
}
function mat3NormalFromMat4(m) {
  // inverse transpose of upper 3x3
  const a = [m[0],m[1],m[2], m[4],m[5],m[6], m[8],m[9],m[10]];
  const det = a[0]*(a[4]*a[8]-a[5]*a[7]) - a[1]*(a[3]*a[8]-a[5]*a[6]) + a[2]*(a[3]*a[7]-a[4]*a[6]);
  const invDet = 1/det;
  return [
    (a[4]*a[8]-a[5]*a[7])*invDet, (a[2]*a[7]-a[1]*a[8])*invDet, (a[1]*a[5]-a[2]*a[4])*invDet,
    (a[5]*a[6]-a[3]*a[8])*invDet, (a[0]*a[8]-a[2]*a[6])*invDet, (a[2]*a[3]-a[0]*a[5])*invDet,
    (a[3]*a[7]-a[4]*a[6])*invDet, (a[1]*a[6]-a[0]*a[7])*invDet, (a[0]*a[4]-a[1]*a[3])*invDet
  ];
}

// --- Render hero ---
function renderHero(t) {
  gl.viewport(0,0,gl.drawingBufferWidth, gl.drawingBufferHeight);
  gl.clearColor(0.07, 0.07, 0.07, 1.0);
  gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
  gl.enable(gl.DEPTH_TEST);
  gl.enable(gl.CULL_FACE);
  gl.cullFace(gl.BACK);

  const aspect = gl.drawingBufferWidth / gl.drawingBufferHeight;
  const projection = mat4Perspective(45*Math.PI/180, aspect, 0.1, 100);
  const view = mat4LookAt([0,0,5], [0,0,0], [0,1,0]);
  const yaw = t * Math.PI * 2;
  const pitch = t * Math.PI * 2;
  const model = mat4Multiply(mat4RotateY(yaw), mat4RotateX(pitch));
  const modelView = mat4Multiply(view, model);
  const normalMatrix = mat3NormalFromMat4(modelView);

  const lightDirWorld = [1, 2, -1];
  const lightDirView = mat4MultiplyVec3(view, lightDirWorld);
  const ll = Math.hypot(...lightDirView);
  const lightDirViewNorm = [lightDirView[0]/ll, lightDirView[1]/ll, lightDirView[2]/ll];

  gl.useProgram(program);
  gl.uniformMatrix4fv(uModelView, false, new Float32Array(modelView));
  gl.uniformMatrix4fv(uProjection, false, new Float32Array(projection));
  gl.uniformMatrix3fv(uNormalMatrix, false, new Float32Array(normalMatrix));
  gl.uniform3fv(uLightDir, lightDirViewNorm);
  gl.uniform3fv(uViewPos, [0,0,0]);
  gl.uniform3fv(uMetalColor, [1.0, 0.85, 0.2]); // gold
  gl.uniform1f(uShininess, 120.0);

  gl.activeTexture(gl.TEXTURE0); gl.bindTexture(gl.TEXTURE_2D, frontTexture); gl.uniform1i(uFrontTexture, 0);
  gl.activeTexture(gl.TEXTURE1); gl.bindTexture(gl.TEXTURE_2D, backTexture); gl.uniform1i(uBackTexture, 1);

  bindBuffers(frontBuffers); gl.drawArrays(gl.TRIANGLE_FAN, 0, frontCount);
  bindBuffers(backBuffers); gl.drawArrays(gl.TRIANGLE_FAN, 0, backCount);
  bindBuffers(sideBuffers); gl.drawArrays(gl.TRIANGLE_STRIP, 0, sideCount);
}

// ============ Edition 2D Coins ============
function drawEditionCoin(canvas, edition) {
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  const cx = w/2, cy = h/2;
  const radius = Math.min(w,h)/2 - 10;

  const metals = {
    bronze: { base: '#CD7F32', light: '#E8A87C', dark: '#8B5A2B' },
    silver: { base: '#C0C0C0', light: '#E8E8E8', dark: '#808080' },
    gold:   { base: '#FFD700', light: '#FFF0A0', dark: '#B8860B' },
    black:  { base: '#1a1a1a', light: '#333333', dark: '#000000' }
  };
  const m = metals[edition];

  // Face gradient
  const grad = ctx.createRadialGradient(cx - radius*0.3, cy - radius*0.3, 0, cx, cy, radius);
  grad.addColorStop(0, m.light);
  grad.addColorStop(0.5, m.base);
  grad.addColorStop(1, m.dark);
  ctx.beginPath(); ctx.arc(cx, cy, radius, 0, Math.PI*2); ctx.fillStyle = grad; ctx.fill();

  // Reeded edge
  ctx.save(); ctx.translate(cx, cy);
  const edgeWidth = 8, reeds = 64;
  for (let i=0;i<reeds;i++) {
    const a = (i/reeds)*Math.PI*2;
    const x1 = (radius-edgeWidth)*Math.cos(a), y1 = (radius-edgeWidth)*Math.sin(a);
    const x2 = radius*Math.cos(a), y2 = radius*Math.sin(a);
    ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2);
    ctx.strokeStyle = i%2===0 ? m.light : m.dark; ctx.lineWidth = 2; ctx.stroke();
  }
  ctx.restore();

  // Emblem
  ctx.save(); ctx.translate(cx, cy);
  ctx.font = `bold ${radius*0.6}px serif`;
  ctx.fillStyle = m.dark;
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.fillText('W', 0, 0);
  ctx.restore();
}

// Draw all edition canvases
document.querySelectorAll('.edition-canvas').forEach(c => {
  drawEditionCoin(c, c.parentElement.dataset.edition);
});

// ============ Demo API ============
let animId = null, paused = false;
function animate(ts) {
  if (paused) return;
  const t = (ts * 0.0005) % 1; // 2s per loop
  renderHero(t);
  animId = requestAnimationFrame(animate);
}
function start() { paused = false; animId = requestAnimationFrame(animate); }
function pause() { paused = true; if (animId) cancelAnimationFrame(animId); animId = null; }

window.demo = {
  canvas: heroCanvas,
  setTime(t) { renderHero(t); },
  pause
};

start();
</script>
</body>
</html>
```
